import sys

input = sys.stdin.read

def main():
    data = input().strip().splitlines()
    t = int(data[0])
    results = []
    for i in range(1, t + 1):
        line = data[i].split('|')[0].strip()
        parts = line.split()
        name = parts[0]
        if 'has' in parts:
            N = int(parts[2])
            M = int(parts[6])
            results.append(N + M)
        elif 'had' in parts:
            N = int(parts[2])
            M = int(parts[6])
            if M <= N:
                results.append(N - M)
            else:
                results.append('INVALID')
        elif 'gives' in parts:
            N = int(parts[2])
            M = int(parts[6])
            if M <= N:
                results.append(N - M)
            else:
                results.append('INVALID')
    for result in results:
        print(result)

if __name__ == '__main__':
    main()
